        async Printer(
            Printer,
            linkpdf,
            copies,
            auth = null,
            multiple_boxes = false
        ) {
            qz.security.setCertificatePromise((resolve, reject) => {
                this.$http
                    .get("/api/qz/crt/override", {
                        responseType: "text"
                    })
                    .then(response => {
                        resolve(response.data);
